alter table public.profiles enable row level security; alter table public.clients enable row level security; alter table public.tax_returns enable row level security; alter table public.status_history enable row level security; alter table public.payments enable row level security; create or replace function public.is_active_employee() returns boolean language sql stable security definer set search_path = public as $$ select exists ( select 1 from public.profiles where profiles.id = auth.uid() and profiles.active = true ); $$; create or replace function public.is_administrator() returns boolean language sql stable security definer set search_path = public as $$ select exists ( select 1 from public.profiles where profiles.id = auth.uid() and profiles.active = true and profiles.role = 'administrator' ); $$; create policy "Employees view their own profile" on public.profiles for select to authenticated using (id = auth.uid()); create policy "Administrators view all profiles" on public.profiles for select to authenticated using (public.is_administrator()); create policy "Administrators update profiles" on public.profiles for update to authenticated using (public.is_administrator()) with check (public.is_administrator()); create policy "Employees view clients" on public.clients for select to authenticated using (public.is_active_employee()); create policy "Employees create clients" on public.clients for insert to authenticated with check ( public.is_active_employee() and created_by = auth.uid() ); create policy "Employees update clients" on public.clients for update to authenticated using (public.is_active_employee()) with check (public.is_active_employee()); create policy "Administrators delete clients" on public.clients for delete to authenticated using (public.is_administrator()); create policy "Employees view returns" on public.tax_returns for select to authenticated using (public.is_active_employee()); create policy "Employees create returns" on public.tax_returns for insert to authenticated with check ( public.is_active_employee() and created_by = auth.uid() ); create policy "Employees update returns" on public.tax_returns for update to authenticated using (public.is_active_employee()) with check (public.is_active_employee()); create policy "Administrators delete returns" on public.tax_returns for delete to authenticated using (public.is_administrator()); create policy "Employees view status history" on public.status_history for select to authenticated using (public.is_active_employee()); create policy "Employees create status history" on public.status_history for insert to authenticated with check ( public.is_active_employee() and changed_by = auth.uid() ); create policy "Employees view payments" on public.payments for select to authenticated using (public.is_active_employee()); create policy "Employees create payments" on public.payments for insert to authenticated with check (public.is_active_employee()); create policy "Administrators update payments" on public.payments for update to authenticated using (public.is_administrator()) with check (public.is_administrator()); create policy "Administrators delete payments" on public.payments for delete to authenticated using (public.is_administrator());